import React from "react"
import { properties } from '../../properties/properties.js'
import Select from 'react-select'
import Popup from 'reactjs-popup'
import 'reactjs-popup/dist/index.css'



class ReplaceStep extends React.Component {
    constructor(props) {
        super(props);
        this.state = {indexSelected: {}, changeText: ""};
    }

    onChangeIndex = (selectedOptions) => {
        this.setState({indexSelected: selectedOptions})
    }



    editStepFunction = (evt) => {
        var result = this.props.indexStep
        var singleResult = this.props.singleResult

        for (var j in result) {
            if (result[j].index == this.state.indexSelected.value)  {
                result[j].aid = singleResult.id  
                result[j].type = singleResult.type
                result[j].ho = singleResult.ho
                result[j].max_ho = singleResult.max_ho
                result[j].current_ho = singleResult.current_ho
                result[j].census = singleResult.census
                result[j].max_census = singleResult.max_census
                result[j].resintern = singleResult.resintern
                result[j].fullteam = singleResult.fullteam
            }

        }


        this.props.parentCallback(
           result
        );
        //evt.preventDefault();
    }

    componentDidMount() {
        this.setState({selectedOptions: {}})
    }

    render() {


        var options =[]
        for (var j in this.props.indexStep) {
            options.push({label: this.props.indexStep[j].step_name, value: this.props.indexStep[j].index})
        }

        return <Popup trigger={<button style={{marginLeft: "10px"}}>Replace Step</button>} position="right">
        {close => (

            <div className="modal">


                <button className="close" onClick={close}>
                    &times;
                </button>



                <div className="content" style={{textAlign: "center"}}> 
                    <span style={{fontSize: "20px"}}>{this.props.translation}</span>
                    <div>&nbsp;</div>

                    <div>Please select ... </div>
                    <div>
                        <Select isMulti={false} id="upTo" onChange={this.onChangeIndex} options={options} className="basic-multi-select"
                    classNamePrefix="select" value={this.state.mainStepSelected}></Select>
                    </div>

                </div>

                <div className="actions">
                    <button className="button"
                        onClick={() => {this.editStepFunction();close()}}
                    >Replace</button>
                </div>

            </div>
        )}
        </Popup>
    }
}



/*
<AddStep translation={translateString} mainStep={this.state.mainStep} distributionResult={this.state.distributionResult} single={singleResult}>

</AddStep>
*/
class AddStep extends React.Component {
    constructor(props) {
        super(props);
        this.state = {mainStepSelected: {}, changeText: ""};
    }

    onChangeMainStep = (selectedOptions) => {
        this.setState({mainStepSelected: selectedOptions})
    }

    changeText = (evt) => {
        this.setState({changeText: evt.currentTarget.value})
    }


    addStepFunction = (evt) => {
        var result = this.props.distributionResult
        var singleResult = this.props.singleResult
        var tempSingle = {}

        //tempSingle.did = this.state.mainStepSelected.value
        tempSingle.did = this.props.mainStep[0].id
        tempSingle.step_num = this.state.mainStepSelected.label
        tempSingle.index = result.length + 1
        tempSingle.step_name = this.state.changeText
        tempSingle.aid = singleResult.id  
        tempSingle.type = singleResult.type
        tempSingle.ho = singleResult.ho
        tempSingle.max_ho = singleResult.max_ho
        tempSingle.current_ho = singleResult.current_ho
        tempSingle.census = singleResult.census
        tempSingle.max_census = singleResult.max_census
        tempSingle.resintern = singleResult.resintern
        tempSingle.fullteam = tempSingle.fullteam

        result.push(tempSingle)


        this.props.parentCallback(
           result
        );
        //evt.preventDefault();
    }

    componentDidMount() {
        this.setState({selectedOptions: {}})
    }

    render() {


        var options =[]
        for (var j in this.props.mainStep) {
            options.push({label: this.props.mainStep[j].step_num, value: this.props.mainStep[j].id})
        }


        var buttonEnable = false
        if (this.state.changeText != "")
        buttonEnable = true

        return <Popup trigger={<button style={{marginLeft: "10px"}}>Add to distribution</button>} position="right">
        {close => (

            <div className="modal">


                <button className="close" onClick={close}>
                    &times;
                </button>



                <div className="content" style={{textAlign: "center"}}> 
                    <span style={{fontSize: "20px"}}>{this.props.translation}</span>
                    <div>&nbsp;</div>

                    <div>Please enter name ...</div>
                    <div className="content" style={{textAlign: "center"}}> 
                      <input style={{width: "320px", height: "35px", border: "solid 1px lightgrey"}} id="stepNameText" onChange={this.changeText}></input>
                </div>


                </div>

                <div className="actions">
                    <button className="button" enabled={{buttonEnable}}
                        onClick={() => {this.addStepFunction();close()}}
                    >Add to distribution</button>
                </div>

            </div>
        )}
        </Popup>
    }
}



class EditStep extends React.Component {


    constructor(props) {
        super(props);
        this.state = { changeText: ""
        };
    }

    chagneName = (evt) => {
        var result = this.props.distributionResult
        for (var i in result) {
            if (result[i].index == this.props.index) {
                result[i].step_name = this.state.changeText
            }
        }
        this.props.parentCallback(
           result
        );
        //evt.preventDefault();
    }


    changeText = (evt) => {
        this.setState({changeText: evt.currentTarget.value})
    }


    render() {
        return <Popup trigger={<button style={{marginLeft: "10px"}}>E</button>} position="right">
        {close => (

            <div className="modal">


                <button className="close" onClick={close}>
                    &times;
                </button>

                <div className="header">
                    {this.props.name}
                </div>


                <div className="content" style={{textAlign: "center"}}> 
                      <input id="changeStepNameTxt" onChange={this.changeText}></input>
                </div>

                <div className="actions">
                    <button className="button"
                        onClick={() => {this.chagneName();close()}}
                    >save</button>
                </div>

            </div>
        )}
        </Popup>
    }
}



class CyberAdmin extends React.Component {


    constructor(props) {
        super(props);
        this.state = { screen: 1, result: [], distributionResult: [], mainStep: [],
            ho: {}, team: {}, startCensusFewer: {}, maxho: {}, resintern: {}, fullteam: {},
            startingCensus: "", upCensus: "", openEidtName: false, permission: false
        };

    }

    editName = (evt) => {
        this.setState({openEidtName: true})
    }

    closeEdit = () => {
        this.setState({openEidtName: false})
    }

    upStep = (evt) => {

        this.setState({screen: 0})
        var setIndex = Number(evt.currentTarget.value)
        if (setIndex == 1) {
            alert("already at first")
        } else {
            var temp = this.state.distributionResult
            //var stop = false
            for (var i in temp) {
                //if (!stop) {
                    if (temp[i].index == setIndex - 1) {
                        temp[i].index = setIndex
                    } else {
                        if (temp[i].index == setIndex) {
                            temp[i].index = setIndex - 1
                            //stop = true
                        }
                    }
                //}
            }
            this.setState({distributionResult: temp})
        }

        this.setState({screen: 1})
    }

    downStep = (evt) => {

        this.setState({screen: 0})
        var setIndex = Number(evt.currentTarget.value)
        if (setIndex == this.state.distributionResult.length) {
            alert("already at last")
        } else {
            var temp = this.state.distributionResult
            var stop = false
            for (var i in temp) {
                if (temp[i].index == setIndex + 1) {
                    temp[i].index = setIndex
                } else {
                    if (temp[i].index == setIndex) {
                        temp[i].index = setIndex + 1
                    }
                }
            }
            this.setState({distributionResult: temp})
        }


        this.setState({screen: 1})
    }


    onChangeNumberOnlyStartingCensus = (e) =>{
        const re = /^[0-9\b]+$/;
        if (e.target.value === '' || re.test(e.target.value)) {
           this.setState({startingCensus: e.target.value})
        }
     }


     onChangeNumberOnlyUpCensus = (e) => {
        const re = /^[0-9\b]+$/;
        if (e.target.value === '' || re.test(e.target.value)) {
           this.setState({upCensus: e.target.value})
        }
     }



    onChangeAssignHO = (selectedOptions) => {
        this.setState({ho: selectedOptions})
    }

    onChangeTeam = (selectedOptions) => {
        this.setState({team: selectedOptions})
    }


    onChangeStartingCensus = (selectedOptions) => {
        this.setState({startCensusFewer: selectedOptions})
    }

    onChangeMaxHo = (selectedOptions) => {
        this.setState({maxho: selectedOptions})
    }

    onChangeResintern = (selectedOptions) => {
        this.setState({resintern: selectedOptions})
    }

    onChangeFullTeam = (selectedOptions) => {
        this.setState({fullteam: selectedOptions})
    }



    deleteStep = (evt) => {
        var distributionResult = this.state.distributionResult
        var setIndex = Number(evt.currentTarget.value)
        var startDelete = false
        var tempResult = []
        for (var i in distributionResult) {
            if (distributionResult[i].index == setIndex) {
                startDelete = true
            } else {
                if (startDelete) {
                    distributionResult[i].index -= 1
                } 
                tempResult.push(distributionResult[i])
            }
        }
        this.setState({distributionResult: tempResult})
    }



    createNewAlgorithm = (evt) => {
        this.setState({screen: 2})
    }

    cancelCreate = () => {
        this.setState({ho: {}})
        this.setState({team: {}})
        this.setState({startCensusFewer: {}})
        this.setState({maxho: {}})
        this.setState({resintern: {}})
        this.setState({fullteam: {}})
        this.setState({startingCensus: ""})
        this.setState({upCensus: ""})
        this.setState({screen: 1})
    }



    handleCreateAlgorithm = () => {


        var errorMsg = ""

        if (JSON.stringify(this.state.ho) == "{}") {
            errorMsg += "please select how many/position HO assign\n"
        }

        if (JSON.stringify(this.state.team) == "{}") {
            errorMsg += "please select which team\n"
        }


        if ((JSON.stringify(this.state.startCensusFewer) != "{}" && this.state.startCensusFewer.value != "") && this.state.startingCensus == "") {
            console.log(this.state.startCensusFewer.value)
            errorMsg += "please enter starting census #\n"
        }

        if (errorMsg == "") {
            var requestData = {}
            if (this.state.ho.value === "1stHO") {
                requestData.ho = 1
                requestData.current_ho = 0
            }
            if (this.state.ho.value === "2ndHO") {
                requestData.ho = 1
                requestData.current_ho = 1
            }
            if (this.state.ho.value === "3rdHO") {
                requestData.ho = 1
                requestData.current_ho = 2
            }
            if (this.state.ho.value === "4thHO") {
                requestData.ho = 1
                requestData.current_ho = 3
            }
            if (this.state.ho.value === "upto1") {
                requestData.ho = 1
            }
            if (this.state.ho.value === "upto2") {
                requestData.ho = 2
            }
            if (this.state.ho.value === "upto3") {
                requestData.ho = 3
            }
            if (this.state.ho.value === "upto4") {
                requestData.ho = 4
            }
            requestData.type = this.state.team.value


            if (JSON.stringify(this.state.startCensusFewer) != "{}" && this.state.startCensusFewer.value != "" && this.state.startingCensus != "") {
                requestData.census = this.state.startingCensus
                if (this.state.startCensusFewer.value == "fewer") {
                    requestData.census = this.state.startingCensus * -1
                }
            } else {
                if (this.state.startingCensus != "") {
                    requestData.census = this.state.startingCensus
                }
            }
            if (this.state.upCensus != "") {
                requestData.max_census = this.state.upCensus
            }
            if (JSON.stringify(this.state.maxho) != "{}") {
                requestData.max_ho = this.state.maxho.value
            }
            if (JSON.stringify(this.state.resintern) != "{}") {
                requestData.resintern = false
                if (this.state.resintern.value == "yes") 
                    requestData.resintern = true
            }
            if (JSON.stringify(this.state.fullteam) != "{}") {
                requestData.fullteam = false
                if (this.state.fullteam.value == "yes") 
                    requestData.fullteam = true
            }





            console.log(requestData)
            this.submitCreateAlgorithm(requestData)
        } else {
            alert(errorMsg)
        }


          //this.submitPage(pageRequest, oldValue)


    }


    submitCreateAlgorithm = (requestData) => {
        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/createalgorithm`
        fetch(backUrl, {
          "method": "POST",
          headers: headers,
          body: JSON.stringify(requestData)

        })
        .then(response => response.json())
        .then(response => {
            if (response.message != "success") {
                this.setState({screen: 2})
                alert(response.message)

            } else {
                this.setState({result: response.result})
                this.setState({distributionResult: response.distributionResult})
                this.setState({mainStep: response.mainStep})
                this.setState({permission: response.permission})
                this.cancelCreate()
            }
        })
        .catch(err => {
          console.log(err);
        });

      }

      submitChangeAlgorithm = () => {
        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/changealgorithm`
        fetch(backUrl, {
          "method": "POST",
          headers: headers,
          body: JSON.stringify(this.state.distributionResult)

        })
        .then(response => response.json())
        .then(response => {
            if (response.message != "success") {
                this.setState({screen: 1})
                alert(response.message)

            } else {
                this.setState({result: response.result})
                this.setState({distributionResult: response.distributionResult})
                this.setState({mainStep: response.mainStep})
                this.setState({permission: response.permission})
                this.cancelCreate()
                alert("saved successfully")
            }
        })
        .catch(err => {
          console.log(err);
        });

      }


      submitResetAlgorithm = () => {
        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/resetalgorithm`
        fetch(backUrl, {
          "method": "POST",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            if (response.message != "success") {
                this.setState({screen: 1})
                alert(response.message)

            } else {
                this.setState({result: response.result})
                this.setState({distributionResult: response.distributionResult})
                this.setState({mainStep: response.mainStep})
                this.setState({permission: response.permission})
                this.cancelCreate()
                alert("algorithm has been resetted")
            }
        })
        .catch(err => {
          console.log(err);
        });

      }



      handleChangeAlgorithm = () => {
        if (window.confirm("are you sure to change algorithm?")) { 
            this.submitChangeAlgorithm()
        }
      }

        handleResetAlgorithm = () => {
            if (window.confirm("are you sure resetting to last algorithm?")) { 
                this.submitResetAlgorithm()
            }
        }



    translateFunction = (singleResult) => {



            var translateString = ""

            var resFull = ""
            if (singleResult.resintern) {
                resFull = " if resintern day"
            }
            if (singleResult.resintern != null && !singleResult.resintern) {
                resFull = " (non-resintern)"
            }
            if (singleResult.fullteam) {
                resFull = " if full team present"
            }

            var teamString = "each " + singleResult.type + " team" + resFull

            //********************************************************************** */
            var maxCensus = ""
            if (singleResult.max_census) {
                maxCensus = ", up to census of " + singleResult.max_census
            }

            //********************************************************************** */
            var maxHO = ""
            if (singleResult.max_ho) {
                maxHO = " (max* " + singleResult.max_ho + " HO)"
            }


            if (singleResult.current_ho || singleResult.current_ho == 0) {
                var num 
                if (singleResult.current_ho + 1 === 1) 
                    num = "st"
                if (singleResult.current_ho + 1 === 2) 
                    num = "nd"
                if (singleResult.current_ho + 1 == 3) 
                    num = "rd"
                if (singleResult.current_ho + 1 > 3) 
                    num = "th"

                translateString += (singleResult.current_ho + 1) + num + " HO to " + teamString

                if (singleResult.census) {
                    if (singleResult.census < 0) {
                        translateString += " with starting census of " + singleResult.census * -1 + " or fewer"
                    } else {
                        translateString += " with starting census of " + singleResult.census
                    }
                }

                translateString += maxCensus + maxHO

            } else {
                if (singleResult.ho > 1)
                    translateString = "Up to " + singleResult.ho + " HO to " + teamString
                else 
                    translateString = singleResult.ho + " HO to " + teamString

                translateString += maxCensus + maxHO


            }


            return translateString



    }





    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/algorithms`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({result: response.avaliableAlgorthim})
            this.setState({distributionResult: response.distributionAlgorithm})
            this.setState({mainStep: response.mainStep})
            this.setState({permission: response.permission})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }

    handleCallback = (childData) => {
        // Update the name in the component's state
       this.setState({ distributionResult: childData });

    };


    render() {


        var header = "Loading ..."
        var content = []
        var borderStyleString = "1px solid black"
        var divStyleString = {marginTop: "10px"}
        var marginTop = "10px"
        var redColor = {color: "red"}
        var divStyleDoubleString = {marginTop: "20px"}



        if (!this.state.permission) {

            content.push(<div>You don't have permission for this application! Please contact Keith Siu - keith.siu@ucsf.edu</div>)

            header = ""
        }






        if (this.state.screen == 2 && this.state.permission) {
            header = ""




            content.push(<div style={divStyleString}><span style={{fontSize: '20px'}}>Create New Step</span></div>)

            content.push(<div style={{divStyleString}}>&nbsp;</div>)


            content.push(<div style={{divStyleString}}><span style={redColor}>* is required</span></div>)


            content.push(<div style={divStyleString}><span style={redColor}>*</span> How many/which HO should be assigned in this step?</div>)


            var options = [
                {label: '1st HO', value: '1stHO'},
                {label: '2nd HO', value: '2ndHO'},
                {label: '3rd HO', value: '3rdHO'},
                {label: '4th HO', value: '4thHO'},
                {label: '1 HO', value: 'upto1'},
                {label: 'Up to 2 HO', value: 'upto2'},
                {label: 'Up to 3 HO', value: 'upto3'},
                {label: 'Up to 4 HO', value: 'upto4'}
              ]


            content.push(<div style={{marginTop: marginTop, width: "300px"}}>
                <Select isMulti={false} id="upTo" onChange={this.onChangeAssignHO} options={options} className="basic-multi-select"
            classNamePrefix="select" value={this.state.ho}></Select> </div>)

            content.push(<div style={divStyleString}><hr></hr></div>)


            content.push(<div style={divStyleString}><span style={redColor}>*</span> Which team?</div>)


            options = [
                {label: 'call', value: 'call'},
                {label: 'GMS', value: 'GMS'},
                {label: 'postpost', value: 'postpost'}
              ]


            content.push(<div style={{marginTop: marginTop, width: "300px"}}>
                <Select isMulti={false} id="upTo" onChange={this.onChangeTeam} options={options} className="basic-multi-select"
            classNamePrefix="select" value={this.state.team}></Select></div>)


            content.push(<div style={divStyleString}><hr></hr></div>)

            options = [
                {label: '', value: ''},
                {label: 'equal', value: 'equal'},
                {label: 'fewer', value: 'fewer'}
              ]


            content.push(<div style={divStyleDoubleString}>Starting census of &nbsp;
            <input style={{width: "50px", height: "35px", border: "solid 1px lightgrey"}} id="startcensus" onChange={this.onChangeNumberOnlyStartingCensus} 
            value={this.state.startingCensus}></input>&nbsp;Or</div>)

            content.push(<div style={{marginTop: marginTop, width: "230px"}}>
                <Select isMulti={false} id="startingCensusSelect" onChange={this.onChangeStartingCensus} options={options} className="basic-multi-select"
            classNamePrefix="select" value={this.state.startCensusFewer}></Select></div>)

            content.push(<div style={divStyleString}><hr></hr></div>)


            content.push(<div style={divStyleDoubleString}>Up to census of &nbsp;
            <input style={{width: "50px", height: "35px", border: "solid 1px lightgrey"}} id="upcensus" onChange={this.onChangeNumberOnlyUpCensus} value={this.state.upCensus}></input></div>)

            content.push(<div style={divStyleString}><hr></hr></div>)



            options = [
                {label: '', value: ''},
                {label: '1 HO', value: '1'},
                {label: '2 HO', value: '2'},
                {label: '3 HO', value: '3'},
                {label: '4 HO', value: '4'}
              ]


              content.push(<div style={divStyleDoubleString}>Max HO</div>)
              content.push(<div style={{marginTop: marginTop, width: "230px"}}><Select isMulti={false} id="maxhoSelect" onChange={this.onChangeMaxHo} options={options} className="basic-multi-select"
              classNamePrefix="select" value={this.state.maxho}></Select></div>)



            content.push(<div style={divStyleString}><hr></hr></div>)


            options = [
                {label: '', value: ''},
                {label: 'Yes', value: 'yes'},
                {label: 'No', value: 'no'}
              ]

              content.push(<div style={divStyleDoubleString}>resintern</div>)
              content.push(<div style={{marginTop: marginTop, width: "230px"}}><Select isMulti={false} id="resinternSelect" onChange={this.onChangeResintern} options={options} className="basic-multi-select"
              classNamePrefix="select" value={this.state.resintern}></Select></div>)


              content.push(<div style={divStyleString}><hr></hr></div>)

              content.push(<div style={divStyleDoubleString}>full team</div>)
              content.push(<div style={{marginTop: marginTop, width: "230px"}}><Select isMulti={false} id="fullteamSelect" onChange={this.onChangeFullTeam} options={options} className="basic-multi-select"
              classNamePrefix="select" value={this.state.fullteam}></Select></div>)


              content.push(<div style={divStyleString}><hr></hr></div>)

              var buttonStyle = {height: "50px", width: "200px", fontSize: "20px"}

            content.push(<div style={divStyleDoubleString}>
                <button onClick={this.handleCreateAlgorithm} style={buttonStyle}>create algorithm</button>&nbsp;&nbsp;
                <button onClick={this.cancelCreate} style={buttonStyle}>Cancel</button></div>)

        }


        if (this.state.screen == 1 && this.state.permission) {

            //content.push(<PopupExample></PopupExample>)


            header = ""
            var headerColor = "navy"
            var subHeaderColor = "#CCCCCC"
            var headerTextColor = "#FFFFFF"

            var tableContent = []
            tableContent.push(<tr><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px', background: headerColor, color: headerTextColor, textAlign: "center"}} colSpan="3">Available algorithms</td></tr>)


            for (var index in this.state.result) {

                var singleResult = this.state.result[index]


                var letFilter = this.state.distributionResult.filter(rec => rec.aid == singleResult.id)
                if (letFilter.length == 0) {

                    var translateString = this.translateFunction(singleResult)


                    tableContent.push(<tr><td style={{border:  borderStyleString, padding: '10px', backgroundColor: "#FFFFE0"}}>{translateString}</td>
                    <td style={{border:  borderStyleString, padding: '10px', backgroundColor: "#FFFFE0"}}>
                        <AddStep parentCallback={this.handleCallback} translation={translateString} mainStep={this.state.mainStep} distributionResult={this.state.distributionResult} singleResult={singleResult}>

                        </AddStep>
                    </td>
                    <td style={{border:  borderStyleString, padding: '10px', backgroundColor: "#FFFFE0"}}>
                        <ReplaceStep parentCallback={this.handleCallback} translation={translateString} indexStep={this.state.distributionResult} singleResult={singleResult}>

                        </ReplaceStep>
                    </td>
                    </tr>)
                }
            }


            //content.push(<table style={{border: borderStyleString}}>{tableContent}</table>)

            var distributionTableContent = []
            var howManyColumn = 5


            distributionTableContent.push(<tr><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px', backgroundColor: headerColor, color: headerTextColor, textAlign: "center"}} colSpan={howManyColumn}>Distribution Algorithm</td></tr>)


            //var distributionStep = ""

            var distributionResult = this.state.distributionResult


            distributionResult.sort((a,b) => a.index - b.index)


            for (var index2 in distributionResult) {

                var singleDistributionResult = distributionResult[index2]
                var translateString = this.translateFunction(singleDistributionResult)

                /*
                if (distributionStep != singleDistributionResult.step_num) {
                    distributionStep = singleDistributionResult.step_num
                    distributionTableContent.push(<tr><td style={{border:  borderStyleString, fontSize: '20px', padding: '5px', backgroundColor: subHeaderColor}} colSpan={howManyColumn}>
                    {distributionStep}</td></tr>)
                }
*/

                distributionTableContent.push(<tr>
                    <td style={{border:  borderStyleString, padding: '10px'}}>{singleDistributionResult.index}</td>
                    <td style={{border:  borderStyleString, padding: '10px'}}>{singleDistributionResult.step_name}
                    <EditStep parentCallback={this.handleCallback} name={singleDistributionResult.step_name} index={singleDistributionResult.index} distributionResult={this.state.distributionResult} style={{marginLeft: "10px"}}></EditStep>
                    </td>
                    <td style={{border:  borderStyleString, padding: '10px'}}>{translateString}</td>
                    <td style={{border:  borderStyleString, padding: '10px'}}>
                        <button onClick={this.upStep} value={singleDistributionResult.index} >&#x25B2;</button>&nbsp;&nbsp;
                        <button onClick={this.downStep} value={singleDistributionResult.index} >&#x25BC;</button>    
                    </td>
                    <td style={{border:  borderStyleString, padding: '10px'}}><button onClick={this.deleteStep} value={singleDistributionResult.index}>delete</button></td>
                </tr>)

            }



            /*
            content.push(<div style={{margin: "auto", overflow: "hidden"}}>
                <div style={{float: "left"}}>
                    <div style={{marginBottom: "10px"}}><button style={{marginLeft: '12px'}} onClick={this.createNewAlgorithm} >Create New Algorithm</button></div>
                    <table style={{border: borderStyleString, width: "600px"}}>{tableContent}</table>
                </div>
                <div style={{float: "left", width: "100px"}}>&nbsp;</div>
                <div style={{float: "left"}}>
                    <div style={{marginBottom: "10px"}}>
                        <button style={{marginLeft: '12px'}} onClick={this.handleResetAlgorithm} >Reset</button>&nbsp;&nbsp;
                        <button style={{marginLeft: '12px'}} onClick={this.handleChangeAlgorithm} >Save</button> 
                    </div>
                    <table style={{border: borderStyleString, width: "800px"}}>{distributionTableContent}</table>
                </div>
                </div>)
*/


content.push(<div>
    <table>
        <tr>
            <td style={{verticalAlign: "top", width: "500px"}}>

                <div style={{marginBottom: "10px"}}><button style={{marginLeft: '12px'}} onClick={this.createNewAlgorithm} >Create New Step</button></div>
                <table style={{border: borderStyleString}}>{tableContent}</table>

            </td>
            <td style={{width: "100px"}}>&nbsp;</td>
            <td style={{verticalAlign: "top", width: "1000px"}}>
                <div style={{marginBottom: "10px"}}>
                    <button style={{marginLeft: '12px'}} onClick={this.handleResetAlgorithm} >Reset</button>&nbsp;&nbsp;
                    <button style={{marginLeft: '12px'}} onClick={this.handleChangeAlgorithm} >Save</button> 
                </div>
                <table style={{border: borderStyleString}}>{distributionTableContent}</table>
            </td>
        </tr>


    </table>

</div>)




        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
